import{_ as o,c as a,o as t,a5 as r}from"./chunks/framework.CgT1UzWm.js";const p=JSON.parse('{"title":"Changelog v3.2.2 (2025-12-24)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.2.2.md","filePath":"guide/changelog/v3.2.2.md"}'),n={name:"guide/changelog/v3.2.2.md"};function i(s,e,c,l,d,h){return t(),a("div",null,e[0]||(e[0]=[r('<h1 id="changelog-v3-2-2-2025-12-24" tabindex="-1">Changelog v3.2.2 (2025-12-24) <a class="header-anchor" href="#changelog-v3-2-2-2025-12-24" aria-label="Permalink to &quot;Changelog v3.2.2 (2025-12-24)&quot;">​</a></h1><h2 id="version-3-2-2-2025-12-24" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.2.2" target="_blank" rel="noreferrer">3.2.2</a> (2025-12-24) <a class="header-anchor" href="#version-3-2-2-2025-12-24" aria-label="Permalink to &quot;Version [3.2.2](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.2.2) (2025-12-24)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.2.1...3.2.2" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li>Fixed sensitive data exposure in command logs for auth endpoints. When <code>ObfuscateAuthParameterLogValues</code> is enabled (default), query string parameters are now stripped from the logged URL to prevent credentials from appearing in logs.</li><li>Fixed <code>traceId</code> being included in ProblemDetails error responses when <code>ErrorHandlingOptions</code> config section is missing. Now correctly removes <code>traceId</code> by default to match the behavior when the config section exists.</li><li>Fixed SSL config key mismatch: renamed <code>HttpsRedirection</code> to <code>UseHttpsRedirection</code> for consistency with <code>UseHsts</code>.</li><li>Fixed missing <code>TokensPerPeriod</code> property in TokenBucket rate limiter configuration.</li><li>Fixed <code>MetadataQuerySchema</code> comment to accurately describe behavior (when null, no search path is set).</li></ul><h3 id="performance-improvements" tabindex="-1">Performance Improvements <a class="header-anchor" href="#performance-improvements" aria-label="Permalink to &quot;Performance Improvements&quot;">​</a></h3><ul><li>Replaced <code>Task</code> with <code>ValueTask</code> for frequently-called private async methods to reduce heap allocations in hot paths: <ul><li><code>PrepareCommand</code> - called before every query execution</li><li><code>OpenConnectionAsync</code> - often completes synchronously when connection is already open</li><li><code>ReturnErrorAsync</code> - error handling path</li><li><code>Challenge</code> (BasicAuthHandler) - authentication challenge response</li></ul></li></ul>',7)]))}const u=o(n,[["render",i]]);export{p as __pageData,u as default};
